#include <iostream>
#include <stack>
using namespace std;

class Solution {
public:
    void push(int x) {
        if (!isEmpty()) {
            stack[++top] = x;
        } else {
            top = x;
        }
    }

    int pop() {
        if (isEmpty()) {
            return -1;
        } else {
            return stack[top--];
        }
    }

    bool isEmpty() {
        if (top == -1) {
            return true;
        } else {
            return false;
        }
    }

    private:
        int top = -1;
        int stack[100];
};

int main() {
    int n;
    cin >> n;
    s.solve();
    return 0;
}
